// native-mate: card@0.1.0 | hash:adef9e467bdef9e9
import React from 'react'
import { View, Pressable, Image } from 'react-native'
import Animated, { useSharedValue, useAnimatedStyle, withSpring } from 'react-native-reanimated'
import { useTheme, Text, Separator, makeStyles, shadow } from '@native-mate/core'
import { Skeleton } from './skeleton'
import type { CardProps, CardHeaderProps, CardContentProps, CardFooterProps, CardMediaProps } from './card.types'

const sizeTokens = {
  sm: { pad: 12, gap: 8,  radius: 10, headerPad: 12 },
  md: { pad: 16, gap: 10, radius: 14, headerPad: 16 },
  lg: { pad: 20, gap: 12, radius: 18, headerPad: 20 },
}

const useStyles = makeStyles((theme) => ({
  elevated: {
    backgroundColor: theme.colors.surfaceRaised ?? theme.colors.surface,
    borderRadius: 14,
    overflow: 'hidden',
    ...shadow(2),
  },
  outline: {
    backgroundColor: theme.colors.surface,
    borderRadius: 14,
    borderWidth: 1,
    borderColor: theme.colors.border,
    overflow: 'hidden',
  },
  flat: {
    backgroundColor: theme.colors.surface,
    borderRadius: 14,
    overflow: 'hidden',
  },
  ghost: {
    backgroundColor: 'transparent',
    borderRadius: 14,
    overflow: 'hidden',
  },
  skeletonWrap: {
    padding: 16,
    gap: 10,
  },
}))

const AnimatedPressable = Animated.createAnimatedComponent(Pressable)

// ─── CardMedia ────────────────────────────────────────────────────────────────

export const CardMedia: React.FC<CardMediaProps> = ({
  source,
  height = 180,
  roundedTop = true,
  style,
}) => {
  return (
    <Image
      source={source}
      style={[
        { width: '100%', height },
        roundedTop && { borderTopLeftRadius: 14, borderTopRightRadius: 14 },
        style,
      ]}
      resizeMode="cover"
    />
  )
}

// ─── CardHeader ───────────────────────────────────────────────────────────────

export const CardHeader: React.FC<CardHeaderProps> = ({
  title,
  subtitle,
  description,
  leading,
  trailing,
  style,
}) => {
  return (
    <View style={[{ paddingHorizontal: 16, paddingTop: 16, paddingBottom: description ? 8 : 12 }, style]}>
      <View style={{ flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between', gap: 12 }}>
        {leading != null && <View style={{ flexShrink: 0 }}>{leading}</View>}
        <View style={{ flex: 1, gap: 2 }}>
          <Text variant="label" style={{ fontSize: 15 }}>{title}</Text>
          {subtitle != null && (
            <Text variant="caption" muted style={{ fontSize: 12 }}>{subtitle}</Text>
          )}
        </View>
        {trailing != null && <View style={{ flexShrink: 0 }}>{trailing}</View>}
      </View>
      {description != null && (
        <Text variant="body" muted style={{ fontSize: 13, marginTop: 8, lineHeight: 20 }}>
          {description}
        </Text>
      )}
    </View>
  )
}

// ─── CardContent ──────────────────────────────────────────────────────────────

export const CardContent: React.FC<CardContentProps> = ({ children, style }) => (
  <View style={[{ paddingHorizontal: 16, paddingBottom: 16 }, style]}>
    {children}
  </View>
)

// ─── CardFooter ───────────────────────────────────────────────────────────────

export const CardFooter: React.FC<CardFooterProps> = ({
  children,
  separated = false,
  align = 'left',
  style,
}) => {
  const justifyContent =
    align === 'right' ? 'flex-end' :
    align === 'apart' ? 'space-between' :
    'flex-start'

  return (
    <>
      {separated && <Separator />}
      <View
        style={[
          {
            flexDirection: 'row',
            alignItems: 'center',
            justifyContent,
            paddingHorizontal: 16,
            paddingVertical: 12,
            gap: 8,
          },
          style,
        ]}
      >
        {children}
      </View>
    </>
  )
}

// ─── Card ─────────────────────────────────────────────────────────────────────

export const Card: React.FC<CardProps> = ({
  children,
  variant = 'elevated',
  size = 'md',
  loading = false,
  onPress,
  disabled = false,
  activeScale = 0.97,
  accent,
  style,
  ...rest
}) => {
  const theme = useTheme()
  const styles = useStyles()
  const scale = useSharedValue(1)

  const animStyle = useAnimatedStyle(() => ({
    transform: [{ scale: scale.value }],
  }))

  const accentStyle = accent != null ? { borderLeftWidth: 3, borderLeftColor: accent } : {}
  const containerStyle = [styles[variant], accentStyle, style]

  const inner = loading ? (
    <View style={styles.skeletonWrap}>
      <Skeleton width="45%" height={13} />
      <Skeleton width="85%" height={11} style={{ marginTop: 2 }} />
      <Skeleton width="70%" height={11} />
      <Skeleton width="35%" height={11} />
    </View>
  ) : (
    children
  )

  if (onPress) {
    return (
      <AnimatedPressable
        onPress={onPress}
        disabled={disabled}
        onPressIn={() => { scale.value = withSpring(activeScale, { damping: 15, stiffness: 300 }) }}
        onPressOut={() => { scale.value = withSpring(1, { damping: 15, stiffness: 300 }) }}
        android_ripple={{ color: theme.colors.border + '50', borderless: false }}
        accessibilityRole="button"
        style={[containerStyle, animStyle, disabled && { opacity: 0.5 }]}
        {...(rest as any)}
      >
        {inner}
      </AnimatedPressable>
    )
  }

  return (
    <View style={containerStyle} {...rest}>
      {inner}
    </View>
  )
}

// native-mate: card@0.1.0 | hash:3e1df5d7c92d133e
import type React from 'react'
import type { ViewProps, ImageSourcePropType, StyleProp, ViewStyle, ImageStyle } from 'react-native'

export type CardVariant = 'elevated' | 'outline' | 'flat' | 'ghost'
export type CardSize = 'sm' | 'md' | 'lg'

export interface CardProps extends Omit<ViewProps, 'style'> {
  children?: React.ReactNode
  variant?: CardVariant
  size?: CardSize
  /** Shows animated skeleton placeholder instead of children */
  loading?: boolean
  /** Makes card pressable with spring animation */
  onPress?: () => void
  disabled?: boolean
  /** Scale on press, default 0.97 */
  activeScale?: number
  /** Accent color painted as a left border stripe */
  accent?: string
  style?: StyleProp<ViewStyle>
}

export interface CardHeaderProps {
  title: string
  subtitle?: string
  description?: string
  /** Avatar or icon rendered on the left */
  leading?: React.ReactNode
  /** Action or badge rendered on the right */
  trailing?: React.ReactNode
  style?: StyleProp<ViewStyle>
}

export interface CardContentProps {
  children: React.ReactNode
  style?: StyleProp<ViewStyle>
}

export interface CardFooterProps {
  children: React.ReactNode
  /** Adds top separator line */
  separated?: boolean
  /** Reverse row direction (right-align actions) */
  align?: 'left' | 'right' | 'apart'
  style?: StyleProp<ViewStyle>
}

export interface CardMediaProps {
  source: ImageSourcePropType
  height?: number
  /** Rounded top corners only (default true) */
  roundedTop?: boolean
  style?: StyleProp<ImageStyle>
}
